import{_ as n,H as a,f as t,i as e}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"一致性模型谱","description":"","frontmatter":{},"headers":[],"relativePath":"distributedLearning/16-一致性模型谱.md","filePath":"distributedLearning/16-一致性模型谱.md","lastUpdated":1778496697000}'),o={name:"distributedLearning/16-一致性模型谱.md"};function i(r,s,p,l,d,c){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="一致性模型谱" tabindex="-1">一致性模型谱 <a class="header-anchor" href="#一致性模型谱" aria-label="Permalink to &quot;一致性模型谱&quot;">​</a></h1><p>前面 09-15 篇讲了<strong>共识</strong>——多个节点怎么对一个值达成一致;但应用层真正要面对的不是「值」,是**「并发操作的历史」**——「我刚写完,另一个客户端读到的是新值还是旧值?」「A、B 两个写并发,后来者会不会看到一个我自己都没经历过的中间态?」<strong>这一整套关于&quot;合法历史&quot;的契约,叫一致性模型(consistency model)</strong>——它跟 ACID 里的 C 没半毛钱关系,跟&quot;数据正确&quot;也不是一回事,<strong>它是数据库 / 存储系统跟你签的合同</strong>:「你能看到的并发执行结果只能长这样,不能长那样」。</p><blockquote><p>一句话先记住:<strong>一致性模型不是&quot;数据对不对&quot;,是&quot;程序员看到的并发历史合不合法&quot;——它是一份契约,规定了哪些读结果可以合理解释,哪些是 bug</strong>。<strong>模型从强到弱是一条谱</strong>——Linearizable ⊃ Sequential ⊃ Causal ⊃ Read-Your-Writes ⊃ Eventual,<strong>越强越像单机,越弱越能扛延迟和分区</strong>。<strong>真实工程不是&quot;选一档&quot;</strong>——同一个系统不同操作走不同档(余额线性、点赞最终),<strong>全选最强系统跑不动,全选最弱用户骂街</strong>。</p></blockquote><hr><h2 id="一、先把术语清干净-三个-c-不要再混" tabindex="-1">一、先把术语清干净:三个 C 不要再混 <a class="header-anchor" href="#一、先把术语清干净-三个-c-不要再混" aria-label="Permalink to &quot;一、先把术语清干净:三个 C 不要再混&quot;">​</a></h2><p>写之前先把&quot;消歧&quot;做掉,这是这一层最容易踩的雷:</p><table tabindex="0"><thead><tr><th>缩写</th><th>全名</th><th>在哪一层</th><th>在保护什么</th></tr></thead><tbody><tr><td><strong>C(ACID)</strong></td><td>Consistency</td><td>数据库事务</td><td>事务后约束(外键、唯一键、check)不被破坏</td></tr><tr><td><strong>C(CAP)</strong></td><td>Consistency</td><td>分布式系统</td><td>实质等同 Linearizability(单对象/单操作级别)</td></tr><tr><td><strong>一致性模型</strong></td><td>Consistency Model</td><td>并发与分布式</td><td>多客户端对同一系统看到的&quot;操作历史&quot;合不合法</td></tr></tbody></table><p><strong>这一篇讲的是第三个</strong>——不是事务约束,也不只是 CAP 里那一档,<strong>是一整张&quot;从最严到最松&quot;的谱</strong>,CAP 的 C 只是这条谱最顶端那一档。</p><blockquote><p>第 03 篇讲过「一致性、共识、一致性模型」三件套,<strong>共识是机器达成一致的算法,一致性模型是程序员能依赖的契约</strong>。共识是手段,模型是目的。</p></blockquote><hr><h2 id="二、为什么需要一个-谱-——直接全用最强不行吗" tabindex="-1">二、为什么需要一个&quot;谱&quot;——直接全用最强不行吗? <a class="header-anchor" href="#二、为什么需要一个-谱-——直接全用最强不行吗" aria-label="Permalink to &quot;二、为什么需要一个&quot;谱&quot;——直接全用最强不行吗?&quot;">​</a></h2><p>朴素想法:都用 Linearizability(看起来像单机)不就行了?</p><p><strong>问题</strong>:Linearizability 在分布式下要付出三个代价:</p><ol><li><strong>每次读写都要走多数派共识</strong>——10ms+ 起步,跨地域 50-100ms</li><li><strong>分区时少数派必须拒服务</strong>——CAP 严格证明(下一篇详细推)</li><li><strong>吞吐天花板低</strong>——所有写串行化进一个全局序</li></ol><p><strong>真实业务的&quot;可容忍延迟 / 错误率&quot;差异巨大</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────┬───────────────────────────────────────┐</span></span>
<span class="line"><span>│ 业务                │ 必须的一致性档位                       │</span></span>
<span class="line"><span>├─────────────────────┼───────────────────────────────────────┤</span></span>
<span class="line"><span>│ 银行转账            │ Linearizable(余额不能错)              │</span></span>
<span class="line"><span>│ 抢购扣库存          │ Linearizable(不能超卖)                │</span></span>
<span class="line"><span>│ 评论列表            │ Causal(评论不能在被回复者之前出现)    │</span></span>
<span class="line"><span>│ 朋友圈刷新          │ Monotonic Read(刷新不能&quot;丢条&quot;)        │</span></span>
<span class="line"><span>│ 点赞数              │ Eventual(几秒内对齐就行)              │</span></span>
<span class="line"><span>│ CDN 内容            │ Eventual(分钟级一致都没事)            │</span></span>
<span class="line"><span>└─────────────────────┴───────────────────────────────────────┘</span></span></code></pre></div><p>如果你把朋友圈的点赞数也跑 Raft,<strong>每秒抗不住几千 QPS</strong>;反过来,如果你把余额跑 eventual,<strong>用户能在 ATM 取出比账上多 100 块的钱</strong>。</p><blockquote><p><strong>一致性是一组档位,不是一个开关</strong>。<strong>应用层的工作 = 给每个数据点选档位</strong>。</p></blockquote><hr><h2 id="三、谱系全景图-强-→-弱" tabindex="-1">三、谱系全景图(强 → 弱) <a class="header-anchor" href="#三、谱系全景图-强-→-弱" aria-label="Permalink to &quot;三、谱系全景图(强 → 弱)&quot;">​</a></h2><p>先一张全景:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  强 ─────────────────────────────────── 弱</span></span>
<span class="line"><span>                  ↓                                       ↓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Strict ⊋ Linearizability ⊋ Sequential ⊋ Causal ⊋ PRAM ⊋ Eventual</span></span>
<span class="line"><span>                  │                │           │       │</span></span>
<span class="line"><span>                  │                │           │       └─ 收敛即可,中间任意</span></span>
<span class="line"><span>                  │                │           │</span></span>
<span class="line"><span>                  │                │           └─ 因果相关有序,并发随意</span></span>
<span class="line"><span>                  │                │</span></span>
<span class="line"><span>                  │                └─ 所有节点同序,但和真实时间无关</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  └─ 每个 op 看起来在 [invoke,resp] 区间内某瞬时原子完成</span></span>
<span class="line"><span>                     真实时间偏序被保留</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   并列的&quot;客户端会话保证&quot;(session guarantees,Terry 1994):</span></span>
<span class="line"><span>     Read-Your-Writes  / Monotonic Reads / Monotonic Writes / Writes-Follow-Reads</span></span>
<span class="line"><span>   ── 这四条是&quot;客户端体验&quot;维度,不在主谱上,但常被叠加在弱模型之上</span></span></code></pre></div><h3 id="_3-1-包含关系-数学" tabindex="-1">3.1 包含关系(数学) <a class="header-anchor" href="#_3-1-包含关系-数学" aria-label="Permalink to &quot;3.1 包含关系(数学)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Strict           ⊋  Linearizability:多了一个&quot;瞬时同步&quot;</span></span>
<span class="line"><span>                                    (上帝视角的绝对时间)</span></span>
<span class="line"><span>Linearizability  ⊋  Sequential:多了&quot;保留真实时间偏序&quot;</span></span>
<span class="line"><span>Sequential       ⊋  Causal:多了&quot;全局顺序&quot;</span></span>
<span class="line"><span>Causal           ⊋  Eventual:多了&quot;因果保持&quot;</span></span></code></pre></div><p>任何 Linearizable 历史都是 Sequential 历史;任何 Sequential 都是 Causal;<strong>反之不成立</strong>。所以&quot;满足强档的系统自动满足弱档&quot;,但反过来不行——这是后面选型的根基。</p><h3 id="_3-2-各档子要记住一句话" tabindex="-1">3.2 各档子要记住一句话 <a class="header-anchor" href="#_3-2-各档子要记住一句话" aria-label="Permalink to &quot;3.2 各档子要记住一句话&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模型</th><th>一句话</th></tr></thead><tbody><tr><td>Strict</td><td>全网瞬时同步(理论玩具,工程上做不到)</td></tr><tr><td>Linearizability</td><td>每个操作看起来&quot;在某一瞬间原子完成&quot;,真实时间偏序保留</td></tr><tr><td>Sequential</td><td>所有客户端看到同一个全局顺序,但顺序可以和真实时间无关</td></tr><tr><td>Causal</td><td>因果相关的操作有序,并发的可以乱序</td></tr><tr><td>Read-Your-Writes</td><td>你自己刚写的,自己后续一定读得到</td></tr><tr><td>Monotonic Reads</td><td>一旦读到版本 v,后面不会读到比 v 更旧的版本</td></tr><tr><td>Monotonic Writes</td><td>同一客户端的写按发起顺序生效</td></tr><tr><td>Writes-Follow-Reads</td><td>你读到 v 后再写的 v&#39;,v&#39; 一定排在 v 之后</td></tr><tr><td>Eventual</td><td>给足时间最终收敛(中间随便)</td></tr></tbody></table><hr><h2 id="四、linearizability-线性一致性" tabindex="-1">四、Linearizability(线性一致性) <a class="header-anchor" href="#四、linearizability-线性一致性" aria-label="Permalink to &quot;四、Linearizability(线性一致性)&quot;">​</a></h2><p>最严的工程档。<strong>直觉</strong>:外部观察者看不出系统是分布式的——所有操作就像在一台原子机上排好队跑完。<strong>下一篇 17 整篇都在讲它</strong>,这里只列要点:</p><ul><li>每个操作占一个 <code>[invocation, response]</code> 区间</li><li>选区间内一个点,作为该操作&quot;原子完成的瞬间&quot;</li><li><strong>不变量</strong>:真实时间偏序保留——op1 在 op2 开始前完成,则线性化序里 op1 必须在 op2 之前</li><li><strong>工程</strong>:Raft / Paxos 单 key 写 + leader read(或 read index / quorum read)</li><li><strong>代价</strong>:跨地域 50-100ms 延迟,分区时不可用</li></ul><p><strong>实例</strong>:etcd / ZooKeeper 默认单 key 写、Spanner 的 External Consistency(比 Linearizability 更严,包含真实时钟顺序)。</p><hr><h2 id="五、sequential-consistency-顺序一致性" tabindex="-1">五、Sequential Consistency(顺序一致性) <a class="header-anchor" href="#五、sequential-consistency-顺序一致性" aria-label="Permalink to &quot;五、Sequential Consistency(顺序一致性)&quot;">​</a></h2><p>Lamport 1979。<strong>比 Linearizable 弱在哪</strong>:<strong>不要求保留真实时间</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>真实时间轴:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Client A:  [-- write x=1 --]</span></span>
<span class="line"><span>  Client B:                       [-- read x ---]  返回 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>线性一致:不合法(B 的读完全晚于 A 的写完成,必须看到 1)</span></span>
<span class="line"><span>顺序一致:合法(全局顺序可以是 read→write,只要所有客户端都这么看)</span></span></code></pre></div><p><strong>经典例子</strong>(单核 CPU 视角):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进程 P1: x = 1; print(y)   →  打印 0</span></span>
<span class="line"><span>进程 P2: y = 1; print(x)   →  打印 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可能吗?</span></span>
<span class="line"><span>顺序一致:不可能(任何全局顺序都至少有一个赋值在另一个 print 前)</span></span>
<span class="line"><span>但弱一致(如 PRAM):可能(每个进程看自己写,别人未必看到)</span></span></code></pre></div><p><strong>工程上</strong>:<strong>顺序一致很少作为主推档</strong>——它比 Causal 严,但比 Linearizable 弱,大多数系统要么直接给 Linearizable,要么退到 Causal。<strong>多核 CPU 内存模型才是 Sequential Consistency 的真正舞台</strong>(Java volatile 不是 Sequential,要 happens-before 才到 Sequential 级别)。</p><hr><h2 id="六、causal-consistency-因果一致性" tabindex="-1">六、Causal Consistency(因果一致性) <a class="header-anchor" href="#六、causal-consistency-因果一致性" aria-label="Permalink to &quot;六、Causal Consistency(因果一致性)&quot;">​</a></h2><p><strong>因果相关有序,并发的随意</strong>。第 18 篇整篇讲它,这里先给直觉:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>case 1(因果相关):</span></span>
<span class="line"><span>  Alice: 发帖 P</span></span>
<span class="line"><span>  Bob:   看到 P,回复 R (R 因果依赖 P)</span></span>
<span class="line"><span>  → 任何客户端必须先看到 P 再看到 R</span></span>
<span class="line"><span>     不能&quot;看到回复,看不到原帖&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>case 2(并发):</span></span>
<span class="line"><span>  Alice: 发帖 P1</span></span>
<span class="line"><span>  Bob:   发帖 P2(同时进行,互不知道)</span></span>
<span class="line"><span>  → 任何客户端可以先看到 P1 也可以先看到 P2,顺序不固定</span></span></code></pre></div><ul><li><strong>判定因果</strong>:happens-before(第 06 篇),靠向量时钟 / 版本向量(第 07 篇)</li><li><strong>代价</strong>:跟踪依赖,<strong>元数据膨胀</strong>(每条消息要带依赖列表)</li><li><strong>好处</strong>:<strong>分区下仍可用</strong>——Mahajan 2011 证明因果可以和 P 并存,<strong>绕开了 CAP 的死结</strong></li></ul><p><strong>工程</strong>:COPS / Bolt-on Causal / Yjs / Google Docs / Figma 协同编辑。</p><hr><h2 id="七、客户端会话保证-session-guarantees" tabindex="-1">七、客户端会话保证(Session Guarantees) <a class="header-anchor" href="#七、客户端会话保证-session-guarantees" aria-label="Permalink to &quot;七、客户端会话保证(Session Guarantees)&quot;">​</a></h2><p>Terry et al. 1994,在 <strong>Bayou</strong> 系统提出。<strong>不是描述系统级历史合法性,而是单个客户端的&quot;观感保障&quot;</strong>——叠加在弱一致系统上的常用补丁。</p><h3 id="_7-1-read-your-writes-读到自己写" tabindex="-1">7.1 Read-Your-Writes(读到自己写) <a class="header-anchor" href="#_7-1-read-your-writes-读到自己写" aria-label="Permalink to &quot;7.1 Read-Your-Writes(读到自己写)&quot;">​</a></h3><p><strong>契约</strong>:同一客户端,write(x=v) 后,后续 read(x) 一定返回 v 或更新值。</p><p><strong>反例</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你刚改了头像 → 主库</span></span>
<span class="line"><span>刷新页面 → 从库(异步复制还没同步)</span></span>
<span class="line"><span>看到旧头像 → 用户:&quot;我改了没生效啊?!&quot;</span></span></code></pre></div><p><strong>实现方式</strong>:</p><ul><li><strong>粘性会话</strong>:同一用户的读写都打到主库 / 同一副本</li><li><strong>读写时间戳</strong>:客户端记下&quot;我写完后的版本号 V&quot;,读时要求服务端返回 ≥ V 的版本</li><li><strong>写后强制主读</strong>:写完后 N 秒内,该用户的读强制走主库</li></ul><h3 id="_7-2-monotonic-reads-单调读" tabindex="-1">7.2 Monotonic Reads(单调读) <a class="header-anchor" href="#_7-2-monotonic-reads-单调读" aria-label="Permalink to &quot;7.2 Monotonic Reads(单调读)&quot;">​</a></h3><p><strong>契约</strong>:一旦读到版本 v,后续读不会返回比 v 更旧的版本(可能比 v 更新)。</p><p><strong>反例</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>9:00:00  刷新朋友圈,看到 100 条</span></span>
<span class="line"><span>9:00:05  又刷一次,只看到 95 条 ←  退化!</span></span>
<span class="line"><span>       (原因:第二次刷打到一个复制更慢的从库)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用户感知:&quot;我朋友圈丢条了!&quot;</span></span></code></pre></div><p><strong>实现</strong>:同一客户端的读固定路由到同一副本,或带版本号要求服务端&quot;≥ 已读版本&quot;才返回。</p><h3 id="_7-3-monotonic-writes-单调写" tabindex="-1">7.3 Monotonic Writes(单调写) <a class="header-anchor" href="#_7-3-monotonic-writes-单调写" aria-label="Permalink to &quot;7.3 Monotonic Writes(单调写)&quot;">​</a></h3><p><strong>契约</strong>:同一客户端的写按发起顺序对外可见。</p><p><strong>反例</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 客户端:write(x=1); write(x=2)</span></span>
<span class="line"><span>B 客户端读到的顺序:x=2, x=1  ←  违反</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用户感知:&quot;我先改了名字 &#39;A&#39;,又改成 &#39;B&#39;,别人看到的却变成 &#39;A&#39;。&quot;</span></span></code></pre></div><h3 id="_7-4-writes-follow-reads" tabindex="-1">7.4 Writes-Follow-Reads <a class="header-anchor" href="#_7-4-writes-follow-reads" aria-label="Permalink to &quot;7.4 Writes-Follow-Reads&quot;">​</a></h3><p><strong>契约</strong>:客户端读到 v 之后再写的 v&#39;,v&#39; 在全局顺序里排在 v 之后。</p><p><strong>用于</strong>:评论引用的语义——你读了原帖才写回复,回复要在原帖之后。</p><blockquote><p><strong>这四条非常常用</strong>,<strong>90% 的&quot;用户感知 bug&quot;都来源于会话保证缺失,而不是底层模型不对</strong>——主库强一致没用,从库没读到自己写,用户就觉得&quot;系统坏了&quot;。</p></blockquote><hr><h2 id="八、各主流系统的默认档位" tabindex="-1">八、各主流系统的默认档位 <a class="header-anchor" href="#八、各主流系统的默认档位" aria-label="Permalink to &quot;八、各主流系统的默认档位&quot;">​</a></h2><p>横向对比一眼能看完(<strong>默认值</strong>,大多数都可调):</p><table tabindex="0"><thead><tr><th>系统</th><th>默认一致性</th><th>可调到</th><th>备注</th></tr></thead><tbody><tr><td><strong>etcd / ZooKeeper</strong></td><td>单 key Linearizable(写),Sequential(读)</td><td>etcd 支持线性化读(--consistency=l)</td><td>Raft / ZAB</td></tr><tr><td><strong>Spanner</strong></td><td>External Consistency(强于 Linearizable)</td><td>—</td><td>TrueTime,跨 key 全局序</td></tr><tr><td><strong>CockroachDB / TiDB</strong></td><td>Linearizable / Serializable</td><td>—</td><td>HLC / TSO + Raft</td></tr><tr><td><strong>DynamoDB</strong></td><td>Eventual(默认)</td><td>Strong consistent read 可选(贵且慢)</td><td>NWR,可调</td></tr><tr><td><strong>Cassandra</strong></td><td>Tunable(默认 ONE = Eventual)</td><td>LOCAL_QUORUM / ALL = 接近 Linearizable</td><td>NWR 三档</td></tr><tr><td><strong>MongoDB</strong></td><td>readConcern = &quot;local&quot;(可能读到未提交主库数据)</td><td>majority / linearizable</td><td>readConcern + writeConcern 笛卡尔积</td></tr><tr><td><strong>Riak</strong></td><td>Eventual + 向量时钟 / Causal+</td><td>bucket type 可选 strong</td><td>主推 Causal</td></tr><tr><td><strong>Redis 主从</strong></td><td>Eventual(主从异步)</td><td>WAIT 命令模拟同步(不保证)</td><td>主挂会丢数据</td></tr><tr><td><strong>Cosmos DB</strong></td><td>Session(读自己写)默认</td><td>Strong / Bounded staleness / Consistent prefix / Eventual 五档可选</td><td><strong>五档明示</strong></td></tr><tr><td><strong>Kafka(单分区)</strong></td><td>单分区内 FIFO + acks=all → 接近 Linearizable</td><td>—</td><td>跨分区无序</td></tr><tr><td><strong>S3</strong></td><td>Read-after-write strong consistency(2020 改)</td><td>—</td><td>历史上是 eventual</td></tr></tbody></table><p><strong>重点观察</strong>:</p><ol><li><strong>NoSQL ≠ AP / 弱一致</strong>——MongoDB / HBase 默认偏 CP,Riak 主推 Causal,<strong>别用标签代替思考</strong></li><li><strong>Cosmos DB 是教科书级&quot;五档明示&quot;</strong>——它把上面这条谱直接做成配置项,<strong>学习一致性模型最好的工程参考</strong></li><li><strong>大多数系统是&quot;可调一致性&quot;</strong>——读写时附加参数选档位(<code>readConcern</code>、<code>consistency level</code>、<code>ReadOptions{LinearizableRead: true}</code>)</li></ol><hr><h2 id="九、选型矩阵-不同业务该走哪一档" tabindex="-1">九、选型矩阵:不同业务该走哪一档 <a class="header-anchor" href="#九、选型矩阵-不同业务该走哪一档" aria-label="Permalink to &quot;九、选型矩阵:不同业务该走哪一档&quot;">​</a></h2><p>这一节就一张表,直接照着对:</p><table tabindex="0"><thead><tr><th>业务类型</th><th>数据例子</th><th>选哪档</th><th>工程方案</th></tr></thead><tbody><tr><td>金融账户</td><td>余额、可用额度</td><td><strong>Linearizable</strong></td><td>Spanner / TiDB / 单库 + 同步复制</td></tr><tr><td>电商扣库存</td><td>商品库存、秒杀名额</td><td><strong>Linearizable</strong>(或预占 + 异步对账)</td><td>Redis Lua + 持久化补偿 / DB select for update</td></tr><tr><td>订单状态</td><td>&quot;已支付&quot;、&quot;已发货&quot;</td><td><strong>Linearizable</strong>(主键级)</td><td>Saga / TCC + 状态机</td></tr><tr><td>用户自己的资料</td><td>头像、昵称</td><td>Eventual + <strong>Read-Your-Writes</strong></td><td>主从异步 + 粘性会话 / 版本号</td></tr><tr><td>社交时间线</td><td>feed、评论</td><td><strong>Causal</strong></td><td>向量时钟 / 因果存储 / 写时打依赖</td></tr><tr><td>协同编辑文档</td><td>Google Docs / Figma</td><td><strong>Causal + CRDT</strong></td><td>操作变换(OT)或 CRDT(第 19 篇)</td></tr><tr><td>点赞 / 关注计数</td><td>微博点赞数</td><td><strong>Eventual + CRDT(G-Counter)</strong></td><td>异步聚合</td></tr><tr><td>缓存查询</td><td>商品详情、推荐</td><td><strong>Eventual</strong></td><td>缓存 + TTL</td></tr><tr><td>配置 / 服务发现</td><td>注册表、灰度配置</td><td><strong>Linearizable(写)</strong> + Eventual(读)</td><td>etcd / ZooKeeper</td></tr><tr><td>锁与选主</td><td>分布式锁、leader 标识</td><td><strong>Linearizable + Fencing</strong>(26 篇)</td><td>etcd / ZK,<strong>禁用 Redis</strong></td></tr></tbody></table><p><strong>反面教材</strong>:</p><ul><li>用 Cassandra 存余额(默认 eventual)——<strong>双花</strong></li><li>用 ZK 存订单详情(写吞吐低)——<strong>写抖动业务挂</strong></li><li>用 Redis 主从存订单状态(主挂丢数据)——<strong>订单丢失</strong></li><li>用 DynamoDB 默认配置做计数器(eventual)——<strong>计数不准但你以为准</strong></li></ul><blockquote><p><strong>绝大多数线上事故 = 业务需要的档位 &gt; 系统提供的档位</strong>。<strong>选型前先问业务要哪档,再问候选系统能提供哪档</strong>。</p></blockquote><hr><h2 id="十、伪代码-三档历史的合法性判定" tabindex="-1">十、伪代码:三档历史的合法性判定 <a class="header-anchor" href="#十、伪代码-三档历史的合法性判定" aria-label="Permalink to &quot;十、伪代码:三档历史的合法性判定&quot;">​</a></h2><p>用 Jepsen 风格的并发历史展示三档差异:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>clients:  C1, C2     register:  x (initial 0)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>history:</span></span>
<span class="line"><span>  C1: invoke write(x, 1) at  t=1</span></span>
<span class="line"><span>  C1: response          at  t=3</span></span>
<span class="line"><span>  C2: invoke read(x)    at  t=2</span></span>
<span class="line"><span>  C2: response 0        at  t=4</span></span>
<span class="line"><span>  C2: invoke read(x)    at  t=5</span></span>
<span class="line"><span>  C2: response 1        at  t=6</span></span>
<span class="line"><span></span></span>
<span class="line"><span>时间轴:</span></span>
<span class="line"><span>  C1: [ write(x,1) ────────────]</span></span>
<span class="line"><span>  C2:        [read=0]    [read=1]</span></span>
<span class="line"><span>       1  2  3  4  5  6  时间</span></span></code></pre></div><p><strong>逐档判定</strong>:</p><ul><li><p><strong>Linearizability</strong>:write 选择&quot;原子点&quot; t∈[1,3],read1 选 t&#39;∈[2,4]。如果 t &lt; t&#39;,read1 必须看到 1;但 read1 返回 0,所以要 t &gt; t&#39;。可行(write 原子点选 t=3,read1 t&#39;=2)。<strong>合法 ✓</strong></p></li><li><p><strong>Sequential</strong>:全局序里同一客户端顺序保留即可。一个合法序:<code>read1=0, write=1, read2=1</code>(C2 的两次读分别在 write 前后)。<strong>合法 ✓</strong></p></li><li><p><strong>Causal</strong>:read1 和 write 无因果关系(read1 没读到 write 的结果),可并发。read2 读到 write 后的值,符合因果。<strong>合法 ✓</strong></p></li></ul><p><strong>反例</strong>(违反线性一致):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>history:</span></span>
<span class="line"><span>  C1: write(x, 1) [t=1,3]</span></span>
<span class="line"><span>  C2: read(x)     [t=4,5]  returns 0     ← 违反:read 完全在 write 之后,必须看到 1</span></span></code></pre></div><p><strong>写工程系统时</strong>用这种小历史去试,<strong>比读教科书快十倍</strong>——拿 Knossos / Porcupine 跑(下一篇详讲)。</p><hr><h2 id="十一、一致性-×-性能-×-可用性的工程权衡" tabindex="-1">十一、一致性 × 性能 × 可用性的工程权衡 <a class="header-anchor" href="#十一、一致性-×-性能-×-可用性的工程权衡" aria-label="Permalink to &quot;十一、一致性 × 性能 × 可用性的工程权衡&quot;">​</a></h2><p><strong>铁律</strong>(PACELC 升级版):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常时:    一致性档位 ↑    →    延迟 ↑     吞吐 ↓</span></span>
<span class="line"><span>分区时:    一致性档位 ↑    →    可用性 ↓</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                  ┌──────────────────────────────────────┐</span></span>
<span class="line"><span>                  │  跨地域 Linearizable 一次写:50-150ms │</span></span>
<span class="line"><span>                  │  跨地域 Causal 一次写:        10-30ms│</span></span>
<span class="line"><span>                  │  跨地域 Eventual 一次写:       &lt;5ms  │</span></span>
<span class="line"><span>                  └──────────────────────────────────────┘</span></span></code></pre></div><p><strong>优化档位的两条工程招式</strong>:</p><h3 id="_11-1-操作级降档" tabindex="-1">11.1 操作级降档 <a class="header-anchor" href="#_11-1-操作级降档" aria-label="Permalink to &quot;11.1 操作级降档&quot;">​</a></h3><p>整库不必全用 Linearizable,<strong>按操作降档</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 余额变更:Linearizable</span></span>
<span class="line"><span>db.transaction(isolation=SERIALIZABLE) {</span></span>
<span class="line"><span>  account.balance -= 100</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 余额查询展示:Eventual + 缓存</span></span>
<span class="line"><span>balance = redis.get(&quot;user:1:balance&quot;) or db.read(consistency=ONE)</span></span></code></pre></div><h3 id="_11-2-数据级分档" tabindex="-1">11.2 数据级分档 <a class="header-anchor" href="#_11-2-数据级分档" aria-label="Permalink to &quot;11.2 数据级分档&quot;">​</a></h3><p><strong>热数据强一致(放主库 / Raft 组),冷数据弱一致(放副本 / 缓存)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>余额、订单状态、扣库存       →  TiDB(Linearizable)</span></span>
<span class="line"><span>用户档案、商品详情、评论     →  MySQL 异步从库(Eventual)</span></span>
<span class="line"><span>点赞计数、推荐结果           →  Redis(Eventual)</span></span></code></pre></div><blockquote><p><strong>没有&quot;系统级一致性&quot;,只有&quot;数据级 / 操作级一致性&quot;</strong>——这是 09 年后所有 NewSQL / 互联网架构的共识。</p></blockquote><hr><h2 id="十二、踩坑提醒" tabindex="-1">十二、踩坑提醒 <a class="header-anchor" href="#十二、踩坑提醒" aria-label="Permalink to &quot;十二、踩坑提醒&quot;">​</a></h2><ol><li><strong>混淆 ACID 的 C 和一致性模型的 C</strong>——前者是事务约束,后者是并发历史合法性,<strong>根本不是一回事</strong></li><li><strong>以为 CAP 的 C 就是&quot;一致性&quot;全部</strong>——它只是 Linearizability 这一档,<strong>下面还有 6-7 档</strong></li><li><strong>整库选一档</strong>——浪费性能或埋雷,正确做法是按操作 / 数据细分</li><li><strong>看到&quot;最终一致&quot;就以为不安全</strong>——大量场景(点赞、推荐、CDN)用最终一致是<strong>最优解</strong></li><li><strong>写完立刻读用从库</strong>——典型违反 Read-Your-Writes,用户感知最差</li><li><strong>不做粘性会话</strong>——同一用户每次打到不同副本,Monotonic Read 必然破</li><li><strong>以为 Spanner 是 Linearizable</strong>——它实际是 <strong>External Consistency</strong>(更强,包含真实时钟序)</li><li><strong>MongoDB 默认 readConcern=local 用了不知道</strong>——读到主库未提交数据,主切换后回滚 = 用户看到的数据消失</li><li><strong>Cassandra 用 QUORUM 就当 Linearizable</strong>——QUORUM 写 + QUORUM 读保证 <strong>read-after-write</strong>,<strong>但不等于 Linearizable</strong>(中间窗口仍能违反)</li><li><strong>跨表 / 跨 key Linearizable</strong>——单 key 强一致 ≠ 跨 key 强一致,<strong>跨 key 要事务或 TrueTime / TSO</strong></li></ol><hr><p>下一篇:<code>17-Linearizability深入.md</code>,把上面这条谱最顶端那一档彻底拆开——<strong>Herlihy &amp; Wing 1990 的定义、CAP 的严格证明、CAS 为什么是 Linearizable 的指标动作、Jepsen 怎么用 Knossos / Porcupine 黑盒测试线性一致性、为什么 etcd / Consul / TiDB / MongoDB / Redis 都被 Jepsen 公开打过脸</strong>。看完你能在 code review 时一眼判断:&quot;这个所谓 Linearizable 实现其实是假的&quot;。</p>`,107)])])}const h=n(o,[["render",i]]);export{u as __pageData,h as default};
